#include <stdio.h>
#include <stdint.h>
#define MOD 1000000007ULL

static uint64_t mod_pow(uint64_t base, uint64_t exp) {
    uint64_t res = 1ULL;
    while (exp) {
        if (exp & 1ULL) res = (res * base) % MOD;
        base = (base * base) % MOD;
        exp >>= 1ULL;
    }
    return res;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        unsigned long long N;
        scanf("%llu", &N);
        if (N == 1ULL) {
            printf("1\n");
        } else if (N == 2ULL) {
            printf("2\n");
        } else {
            int k = 63 - __builtin_clzll(N); // floor(log2 N)
            uint64_t ans = mod_pow(2ULL, (uint64_t)k + 1ULL);
            printf("%llu\n", ans);
        }
    }
    return 0;
}

