import sys
MOD = 1_000_000_007

def mod_pow(b, e):
    res = 1
    while e:
        if e & 1:
            res = (res * b) % MOD
        b = (b * b) % MOD
        e >>= 1
    return res

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        if N == 1:
            out.append('1')
        elif N == 2:
            out.append('2')
        else:
            k = N.bit_length() - 1  # floor(log2 N)
            out.append(str(mod_pow(2, k + 1)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

